class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        result = []
        num = 1
        while len(result) < n:
            # Check if adding num would create a pair summing to k
            valid = True
            for x in result:
                if x + num == k:
                    valid = False
                    break
            if valid:
                result.append(num)
            num += 1
        return sum(result)
